import stripe
from config import Config

stripe.api_key = Config.STRIPE_SECRET_KEY


def create_checkout_session(user_email, success_url, cancel_url):
    """Create a Stripe Checkout session for Pro subscription."""
    session = stripe.checkout.Session.create(
        mode='subscription',
        customer_email=user_email,
        line_items=[{
            'price': Config.STRIPE_PRO_PRICE_ID,
            'quantity': 1
        }],
        success_url=success_url,
        cancel_url=cancel_url
    )
    return session


def verify_webhook(payload, sig_header):
    """Verify and parse a Stripe webhook event."""
    return stripe.Webhook.construct_event(
        payload, sig_header, Config.STRIPE_WEBHOOK_SECRET
    )

from flask import Blueprint, request, jsonify, url_for
from models.user import User
from services.stripe_service import create_checkout_session, verify_webhook

account_bp = Blueprint('account', __name__)

@account_bp.route('/account', methods=['GET'])
def get_account():
    user = User.get_current()
    return jsonify(user.to_dict())

@account_bp.route('/account/subscribe', methods=['POST'])
def subscribe():
    user = User.get_current()
    session = create_checkout_session(
        user_email=user.email,
        success_url=request.host_url + 'account?subscribed=1',
        cancel_url=request.host_url + 'account'
    )
    return jsonify({'checkout_url': session.url})

@account_bp.route('/webhooks/stripe', methods=['POST'])
def stripe_webhook():
    event = verify_webhook(
        request.get_data(), request.headers.get('Stripe-Signature')
    )
    if event['type'] == 'checkout.session.completed':
        email = event['data']['object']['customer_email']
        user = User.query.filter_by(email=email).first()
        if user:
            user.plan = 'pro'
            user.save()
    return jsonify({'status': 'ok'})
